import { Component, OnInit } from '@angular/core';
import { BookService } from '../../services/book.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-book-history',
  templateUrl: './book-history.component.html',
  styleUrls: ['./book-history.component.css']
})
export class BookHistoryComponent implements OnInit {
  userIssuedBooks: any[] = [];
  allIssuedBooks: any[] = [];
  isLoading: boolean = false;
  currentUser: any = null;

  // Filters
  statusFilter: string = 'all';
  searchTerm: string = '';

  constructor(private bookService: BookService, private authService: AuthService) {}

  ngOnInit(): void {
    this.currentUser = this.authService.getCurrentUser();
    this.loadBookHistory();
  }

  loadBookHistory(): void {
    if (this.currentUser) {
      this.userIssuedBooks = this.bookService.getIssuedBooksByUser(this.currentUser.id);
      this.allIssuedBooks = this.bookService.getAllIssuedBooks();
    }
  }

  get filteredUserBooks(): any[] {
    let filtered = [...this.userIssuedBooks];

    // Apply status filter
    if (this.statusFilter !== 'all') {
      filtered = filtered.filter((book: any) => book.status === this.statusFilter);
    }

    // Apply search filter
    if (this.searchTerm) {
      const searchLower = this.searchTerm.toLowerCase();
      filtered = filtered.filter((book: any) => {
        const bookTitle = this.getBookTitle(book.bookId).toLowerCase();
        const bookAuthor = this.getBookAuthor(book.bookId).toLowerCase();
        return bookTitle.includes(searchLower) || bookAuthor.includes(searchLower);
      });
    }

    // Sort by issue date (newest first)
    return filtered.sort((a: any, b: any) => 
      new Date(b.issueDate).getTime() - new Date(a.issueDate).getTime()
    );
  }

  get filteredAllBooks(): any[] {
    let filtered = [...this.allIssuedBooks];

    // Apply status filter
    if (this.statusFilter !== 'all') {
      filtered = filtered.filter((book: any) => book.status === this.statusFilter);
    }

    // Apply search filter
    if (this.searchTerm) {
      const searchLower = this.searchTerm.toLowerCase();
      filtered = filtered.filter((book: any) => {
        const bookTitle = this.getBookTitle(book.bookId).toLowerCase();
        const bookAuthor = this.getBookAuthor(book.bookId).toLowerCase();
        return bookTitle.includes(searchLower) || bookAuthor.includes(searchLower);
      });
    }

    // Sort by issue date (newest first)
    return filtered.sort((a: any, b: any) => 
      new Date(b.issueDate).getTime() - new Date(a.issueDate).getTime()
    );
  }

  getBookTitle(bookId: string): string {
    const book = this.bookService.getBookById(bookId);
    return book ? book.title : 'Unknown Book';
  }

  getBookAuthor(bookId: string): string {
    const book = this.bookService.getBookById(bookId);
    return book ? book.author : 'Unknown Author';
  }

  getUserName(userId: string): string {
    // In a real app, this would fetch user details
    // For demo purposes, we'll return a placeholder
    return `User ${userId}`;
  }

  formatDate(date: Date | string): string {
    const d = new Date(date);
    return d.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  }

  getStatusClass(status: string): string {
    switch (status) {
      case 'issued':
        return 'status-issued';
      case 'returned':
        return 'status-returned';
      case 'overdue':
        return 'status-overdue';
      default:
        return '';
    }
  }

  getStatusText(status: string): string {
    switch (status) {
      case 'issued':
        return '📖 Issued';
      case 'returned':
        return '✅ Returned';
      case 'overdue':
        return '⚠️ Overdue';
      default:
        return status;
    }
  }

  clearFilters(): void {
    this.statusFilter = 'all';
    this.searchTerm = '';
  }

  exportHistory(): void {
    const data = this.isAdmin() ? this.filteredAllBooks : this.filteredUserBooks;
    const csv = this.convertToCSV(data);
    this.downloadCSV(csv, 'book-history.csv');
  }

  convertToCSV(data: any[]): string {
    if (data.length === 0) return '';

    const headers = ['Book Title', 'Author', 'Issue Date', 'Due Date', 'Return Date', 'Status', 'Fine'];
    const rows = data.map(book => [
      this.getBookTitle(book.bookId),
      this.getBookAuthor(book.bookId),
      this.formatDate(book.issueDate),
      this.formatDate(book.dueDate),
      book.returnDate ? this.formatDate(book.returnDate) : 'Not returned',
      this.getStatusText(book.status),
      book.fine ? `₹${book.fine}` : '₹0'
    ]);

    return [headers, ...rows].map(row => row.join(',')).join('\n');
  }

  downloadCSV(csv: string, filename: string): void {
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    window.URL.revokeObjectURL(url);
  }

  isAdmin(): boolean {
    return this.authService.isAdmin();
  }

  getStatistics(): any {
    const books = this.isAdmin() ? this.allIssuedBooks : this.userIssuedBooks;

    return {
      total: books.length,
      issued: books.filter((book: any) => book.status === 'issued').length,
      returned: books.filter((book: any) => book.status === 'returned').length,
      overdue: books.filter((book: any) => book.status === 'overdue').length,
      totalFines: books.reduce((total: number, book: any) => total + (book.fine || 0), 0)
    };
  }
}
<div class="book-history-container">
  <div class="page-header">
    <h1>📊 Book History</h1>
    <p *ngIf="!isAdmin()">View your book borrowing history</p>
    <p *ngIf="isAdmin()">View all book borrowing records</p>
  </div>

  <!-- Statistics Cards -->
  <div class="stats-grid">
    <div class="stat-card">
      <div class="stat-icon">📚</div>
      <div class="stat-content">
        <h3>{{ getStatistics().total }}</h3>
        <p>Total Books</p>
      </div>
    </div>

    <div class="stat-card">
      <div class="stat-icon">📖</div>
      <div class="stat-content">
        <h3>{{ getStatistics().issued }}</h3>
        <p>Currently Issued</p>
      </div>
    </div>

    <div class="stat-card">
      <div class="stat-icon">✅</div>
      <div class="stat-content">
        <h3>{{ getStatistics().returned }}</h3>
        <p>Returned</p>
      </div>
    </div>

    <div class="stat-card">
      <div class="stat-icon">⚠️</div>
      <div class="stat-content">
        <h3>{{ getStatistics().overdue }}</h3>
        <p>Overdue</p>
      </div>
    </div>

    <div class="stat-card">
      <div class="stat-icon">💰</div>
      <div class="stat-content">
        <h3>₹{{ getStatistics().totalFines }}</h3>
        <p>Total Fines</p>
      </div>
    </div>
  </div>

  <!-- Filters -->
  <div class="filters-section">
    <div class="filter-card">
      <h3>Filters</h3>

      <div class="filter-row">
        <div class="form-group">
          <label for="statusFilter">Status</label>
          <select 
            id="statusFilter" 
            name="statusFilter" 
            [(ngModel)]="statusFilter"
            class="filter-select"
          >
            <option value="all">All Status</option>
            <option value="issued">Issued</option>
            <option value="returned">Returned</option>
            <option value="overdue">Overdue</option>
          </select>
        </div>

        <div class="form-group">
          <label for="searchTerm">Search</label>
          <input 
            type="text" 
            id="searchTerm" 
            name="searchTerm" 
            [(ngModel)]="searchTerm" 
            placeholder="Search by book title or author..."
            class="filter-input"
          />
        </div>

        <div class="form-group">
          <label>&nbsp;</label>
          <div class="filter-actions">
            <button class="clear-btn" (click)="clearFilters()">Clear Filters</button>
            <button class="export-btn" (click)="exportHistory()">📥 Export CSV</button>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- History Table -->
  <div class="history-section">
    <div class="section-card">
      <div class="section-header">
        <h2>
          {{ isAdmin() ? 'All Book Records' : 'My Book History' }}
          ({{ isAdmin() ? filteredAllBooks.length : filteredUserBooks.length }})
        </h2>
      </div>

      <div *ngIf="!isAdmin() && filteredUserBooks.length === 0" class="empty-state">
        <div class="empty-icon">📚</div>
        <h3>No book history found</h3>
        <p>You haven't borrowed any books yet.</p>
      </div>

      <div *ngIf="isAdmin() && filteredAllBooks.length === 0" class="empty-state">
        <div class="empty-icon">📚</div>
        <h3>No book records found</h3>
        <p>No book borrowing records match your filters.</p>
      </div>

      <div class="history-table" *ngIf="(!isAdmin() && filteredUserBooks.length > 0) || (isAdmin() && filteredAllBooks.length > 0)">
        <table>
          <thead>
            <tr>
              <th>Book Title</th>
              <th>Author</th>
              <th *ngIf="isAdmin()">User</th>
              <th>Issue Date</th>
              <th>Due Date</th>
              <th>Return Date</th>
              <th>Status</th>
              <th>Fine</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let book of (isAdmin() ? filteredAllBooks : filteredUserBooks)">
              <td class="book-title">{{ getBookTitle(book.bookId) }}</td>
              <td>{{ getBookAuthor(book.bookId) }}</td>
              <td *ngIf="isAdmin()">{{ getUserName(book.userId) }}</td>
              <td>{{ formatDate(book.issueDate) }}</td>
              <td>{{ formatDate(book.dueDate) }}</td>
              <td>{{ book.returnDate ? formatDate(book.returnDate) : 'Not returned' }}</td>
              <td>
                <span class="status-badge" [ngClass]="getStatusClass(book.status)">
                  {{ getStatusText(book.status) }}
                </span>
              </td>
              <td class="fine-amount">
                {{ book.fine ? 'Rs' + book.fine : 'Rs0' }}
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  </div>
</div>
